/**
 * @name Directory traversal via path manipulation
 * @description User-controlled paths may allow directory traversal attacks
 * @kind path-problem
 * @problem.severity error
 * @id py/aiohttp-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import python
import semmle.python.dataflow.new.DataFlow
import semmle.python.dataflow.new.TaintTracking
import semmle.python.ApiGraphs

module PathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(DataFlow::AttrRead attr |
      attr.getAttributeName() in ["path", "raw_path", "rel_url"] and
      source = attr
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(DataFlow::CallCfgNode call |
      (
        call = API::moduleImport("pathlib").getMember("Path").getACall() or
        call = API::builtin("open").getACall()
      ) and
      sink = call.getArg(_)
    )
  }
}

module PathTraversalFlow = TaintTracking::Global<PathTraversalConfig>;
import PathTraversalFlow::PathGraph

from PathTraversalFlow::PathNode source, PathTraversalFlow::PathNode sink
where PathTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential path traversal from $@.", source.getNode(), "user-controlled path"

/**
 * @name Follow symlinks parameter flow to resolve
 * @description Tracks how follow_symlinks parameter affects path resolution
 * @kind path-problem
 * @problem.severity error
 * @id py/aiohttp-follow-symlinks-flow
 * @tags security
 *       external/cwe/cwe-022
 */

import python
import semmle.python.dataflow.new.DataFlow
import semmle.python.dataflow.new.TaintTracking

module FollowSymlinksConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(DataFlow::CallCfgNode call, DataFlow::Node arg |
      call.getFunction().asCfgNode().(NameNode).getId() in ["__init__", "add_static"] and
      arg = call.getArgByName("follow_symlinks") and
      source = arg
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(DataFlow::AttrRead attr |
      attr.getAttributeName() = "resolve" and
      sink.asCfgNode() = attr.getObject().asCfgNode()
    )
  }
}

module FollowSymlinksFlow = TaintTracking::Global<FollowSymlinksConfig>;
import FollowSymlinksFlow::PathGraph

from FollowSymlinksFlow::PathNode source, FollowSymlinksFlow::PathNode sink
where FollowSymlinksFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "follow_symlinks parameter flows to resolve() call from $@.", source.getNode(), "parameter"
